AllDialogue.Voicelines["Nyx"] = {
	["0002"] = "Darkness guide you, child. You have outgrown this House, of that I am now certain. Should you return again here, I shall keep you safe.",
	["0003"] = "Darkness guide you, child.",
	["0004"] = "Take care of yourself, child.",
	["0005"] = "I shall be watching over you, and our House alike.",
	["0006"] = "Do not concern yourself about your father. I shall be watching him.",
	["0007"] = "Fear not for Cerberus. He is well taken care of in your absence, and well-fed.",
	["0008"] = "Go, fulfill your purpose, child.",
	["0009"] = "Your fate lies somewhere past these walls, child.",
	["0010"] = "You are always welcome in my company, child.",
	["0011"] = "Do not despair, and hold to your resolve, child.",
	["0012"] = "Remember there are those who love you, child.",
	["0013"] = "Do not let circumstances rattle your resolve, child.",
	["0014"] = "Thank you for visiting me, child.",
	["0015"] = "Such brief exchanges gladden me, my child.",
	["0016"] = "Your father is the same as ever, child.",
	["0017"] = "Someday, you shall achieve your heart's desire, child.",
	["0018"] = "The life the Fates apportioned to you lies ahead, my child.",
	["0019"] = "May you discover what you seek, my child.",
	["0020"] = "I shall keep you safe during your stay here, child.",
	["0021"] = "I am well, though thank you for your remembering me, child.",
	["0022"] = "I am filled with joy to see you whole, my child.",
	["0023"] = "Always am I grateful for your company, my child.",
	["0024"] = "You are most generous to visit with me, child.",
	["0025"] = "You look rather well on this occasion, child.",
	["0026"] = "It pleases me having these brief exchanges, child.",
	["0027"] = "My faith in you has never faltered, child.",
	["0032"] = "I shall support you however I can, my child.",
	["0045"] = "How can I possibly accept such generosity, my child? Surely others whom you know are more deserving of such offerings.",
	["0046"] = "Your kindness toward me is unnecessary, child. You know I have no expectation of such gifts, from you or anyone.",
	["0047"] = "You honor me, my child; although I dread that I am not deserving of such generosity. There is no need to flatter me like this.",
	["0058"] = "I sense your worry for me, child, yet would seek to disabuse you of the sentiment.",
	["0059"] = "Though your journeys take you elsewhere, still it pleases me to see you, child.",
	["0060"] = "I trust that the Mirror in your bedchamber has proved satisfactory, dear child...?",
	["0061"] = "You appear to have grown stronger since when last we interacted, child. Your bedroom mirror may appear to be the cause... but then of course the real cause is you.",
	["0062"] = "I sense the growing darkness in you, child. I am so very proud of you. You always have been capable, yet now, you seem to radiate with newfound power.",
	["0063"] = "The unfathomable power of the Underworld thrives within you, child. Your godliness has grown since last we spoke; you have learned much of harnessing the dark.",
	["0064"] = "Before you go, my child... your father's mood is rather difficult right now. Perhaps just leave him be.",
	["0065"] = "Oh, my dear child! So now you know...? So now you know. But, only half the truth. I can explain the rest, so, please.... It never was my wish to hurt you.",
	["0066"] = "Your mother yet lives. There can be no other explanation. For, if she did not, she would be with us, here.... She was a good woman. Stately, kind. I wished to raise you as I thought she would have.",
	["0069"] = "You have encountered setbacks within Asphodel, have you not, child? The Bloodless shades residing there are eager to bring death to any form of life. Beware of their infernal power.",
	["0070"] = "Primordial Chaos... indeed, I know them well. They must have taken interest in your quest. I would advise that you beware their offerings, though know that Chaos, whilst a trickster, is not a deceiver.",
	["0071"] = "My place is not to speak too openly of Chaos, child. It is their own prerogative to tell you of themselves. I can say they are the eldest force within this world. Before them, there was nothing.",
	["0072"] = "They mentioned me, did they... I thought, perhaps, that they had long forgotten. You should know they are my mother and my father, child. We have not spoken since the dawn of time.",
	["0073"] = "It is for Chaos to reach out to me if they wish to reacquaint themselves with me. Child, it would please me if we spoke no more of this for now.",
	["0075"] = "The House shall stand eternally, although in what condition, it is ours to decide. Our obligation is to keep the House in order.",
	["0077"] = "The Fury Megaera is under orders to prevent your passage out of Tartarus, my child. Conflict between the two of you is unavoidable. It brings me pain to have to see you fight.",
	["0078"] = "You must have vanquished Megaera, my child, for she has been sulking in the lounge for quite some time. You are safe here from her whip, but not her words.",
	["0080"] = "...And after that, Dusa, you are to clean the rafters once again, and prune the gardens thoroughly. By then it should be time to tend the kitchens, and sweep the lounging area a second time...",
	["0083"] = "Your expertise has readied him, Achilles. Yet I sense it is your confidence in him which spurs him on. Do not lose faith in yourself now, lest soon he do the same.",
	["0084"] = "The gods of Mount Olympus tend to think themselves above us, child. Or so your father often likes to say. He alone was relegated to this realm, and grew resentful of his relatives on high.",
	["0085"] = "Thanatos has finally come home. Have you not seen him, child? He has been very much preoccupied of late. It must have gladdened him to see you once again.",
	["0086"] = "Thanatos is worried for you, child. I hope you understand whatever anger you may sense from him is not the feeling at the source. Please forgive his rudeness.",
	["0087"] = "...Lastly, Dusa, you are not permitted to address the Prince, unless first spoken to. You are invisible to him. Now, are we understood?",
	["0088"] = "Alas, you have seen much of Hypnos lately, child. I hope you find his disposition somewhat tolerable? Please tell me plain if this is not the case.",
	["0089"] = "The Three Fates are my daughters, yes, my child. However, I am no more privy to their workings than the naive mortals living up above. Not even the Olympians can know the weavings of the Fates.",
	["0093"] = "They typically do not. But, you are family, child. And I, why... I believed Athena wise enough to understand why someone such as I would seek her, in particular. She has, in turn, made others in her family aware.",
	["0094"] = "You are enshrouded from them, child. For your own benefit, and theirs. They know as much as necessary to assist. And I trust they shall, for as long as you require. They are bound to one another as family. And they know that you require aid. Do not be too prideful to accept.",
	["0095"] = "I always knew, in turn, that you would learn the truth of it, eventually. And I was fearful of what would occur after that time arrived. I'm grateful it has come and gone. Though, tell me. I still find I call you child. Is your preference that I cease to use such terms, from this point on?",
	["0096?"] = "Somehow, I always knew. You know... that you were not my birthmother. I mean, look at Hypnos and Thanatos. There's no way that I could have been related to them, everybody knew, and yet... when I finally learned for certain, it was still a shock.",
	["0097"] = "Your birthmother left a strong impression on us, child. It was apparent she was from a far-off place, and yet... she brought with her a lightness I had not experienced before. My first impression soon subsided, and I grew to care for her. You possess many of her finer qualities.",
	["0098"] = "Please... you must not ask such things of me. I swore a binding oath never to say. I have already circumvented it as much as can be done. Go find her, child. Then, you shall understand.",
	["0100"] = "Do not despair, as I told you before. With effort and with time, most any setback can be overcome. Even your father. You have come closer to your goal. Achieve it!",
	["0101"] = "You need not fear for me, my child. For I am not some underling your father has authority to punish if it pleases him. I am the Night; and it is by my grace that this House stands. Your father knows this. Thus, he and I have certain common goals. We are obligated to cooperate.",
	["0102"] = "Please... that is something I am not at liberty to say. When you meet your birthmother eventually... you shall understand.",
	["0103"] = "Your father and I... sometimes convince ourselves.",
	["0104"] = "Ah-hahah. I am pleased to see the two of you on better terms of late. Megaera always was as she appears. Dutiful and quite particular. Thoughtful and dependable. Respectful.",
	["0105"] = "...We each have our commitments to this House, Megaera. There is no shame in yours. And whilst your sisters are away, you bear their burden of responsibility, as well.",
	["0107?"] = "...and so, who else is there to be depended on...? You are a trusted overseer, Megaera. Your station is no accident and there is no one better fit for what you do. I urge you to look inwardly. How you approach your work is vital to the end result.",
	["0108"] = "We have an understanding, Hades, yes. He is your own son, after all, and therefore your responsibility. I, in turn, have my commitments to this realm, and to this House. You have aided me in them, so I remain, as ever, in your debt.",
	["0109"] = "Hades, my relationship with him remains unchanged. It is the very same relationship from when you first requested I take care of him. He has my full support, and always shall. You must know this. He wishes now to leave. I shall make no attempt to stop him.",
	["0110"] = "...I was here long before your father. The responsibility to govern fell to me. Yet, I could not manage on my own. I shape the darkness; ensure the integrity of the domain. I am less prone to census-taking and administering rules. I receded from such responsibilities.",
	["0111"] = "I was quite skeptical of him, at first. I thought his presence merely a cruel trick of Fate. But... he worked diligently, from the start. Soon there was order where once there was none. I fashioned this House for him, and I maintain it still. We remain in partnership. In interdependency.",
	["0112"] = "No, child. He has not. He can be short with me, as you have seen. But that is the extent of it. We have found ways to reconcile disagreements. Though, your relationship with him... it is more complicated than my own, I fear...",
	["0113"] = "You have confronted the Exalted Shades within Elysium, my child. Your father offers them a handsome bounty should they bring your journey to an end. Although, I think the pride of vanquishing you would more than suffice in getting them to take up arms again.",
	["0115?"] = "You nearly gained the surface, child. Considerable progress. Though, the setbacks that you faced within the Temple... if it is of any consolation, the foes you faced there have been quite a burden to your father, too.",
	["0116"] = "Your father is not here, and you are back. Then, it can only mean one thing. Are you all right, my child?",
	["0117"] = "You know his weaknesses better than anyone. Better even than he. It pains me to know that the conflict between you could not be settled in some other way. But if this is how it has to be... destroy him for me, next you fight up there. However long it takes. Would you do that?",
	["0118"] = "Lord Hermes is a point of contact, yes. Among Olympians he works the closest with our operations here, and aids with shepherding the souls of the departed to our gates. Accept his help; for he is faithful to our cause.",
	["0119"] = "...Listen to me, child. What you know, or do not know, is for your protection. Your protection, and your birthmother's, as well. Your suspicion and your curiosity are warranted. But I can do no more about them, now, except to caution you. Are we understood?",
	["0120"] = "I saw you took possession of the List of Minor Prophecies, of the Three Fates. As ever, I should never have doubted my daughters' expectations. I was uncertain you had necessary guidance to select it from among the House Contractor's many opportunities.",
	["0121"] = "You know exactly what is necessary, and no more. I know better than anyone never to tamper with the Fates' design. Though, if they had cruelty in store for you through their List... I think that I would warn you, anyway.",
	["0122"] = "You have fulfilled already many prophecies envisioned by my daughters, child. Although perhaps inevitable, I find it impressive, nonetheless.",
	["0123"] = "The Fates have perfect knowledge of exactly what is necessary for the future they have woven to someday come to pass. We each are instrumental to their ultimate design. Some more than others, it would seem, of course.",
	["0124"] = "What is it, child? Is something amiss?",
	["0125"] = "Ah. Yes, no need to speak of it again. Though, I am pleased to oblige.",
	["0126"] = "I thank you for the lovely flowers, child. They make my corner of the House hospitable. Such simple comforts never were for me, and yet... now that I am surrounded by them, I have found that I enjoy their presence, more than I would have admitted in the past.",
	["0127"] = "This point is closest to the center of the House. To its foundation. And, therefore, to the center of the entire realm.",
	["0128"] = "How very forward of you, child. I accept your compliment. Although, I am the Night, as you observe. The night conceals all. I know nothing of the loneliness which you describe. This entire realm... it is a part of me. And many of its subjects sprang from me, alone.",
	["0129"] = "You must have vanquished Megaera, my child. For she has been sulking in the corner there for quite some time. You are safe here from her whip, but not her words.",
	["0130"] = "Neutrality ceases to be an option when a crisis rises to a certain point, Megaera. You, yourself, shall have to choose allegiances. I have steadfastly told you this throughout our shared ordeal.",
	["0131"] = "Use caution with the tone you take with me, Overseer. I am the mother of the Fates, themselves. I do not act by whim or by mistake. Mind your own station, and perform your role. All shall unfold eventually as it must. I like the intervening time no more than you.",
	["0132"] = "To doubt is an important instinct, Megaera. Without it, we could not conceive of better circumstances than the ones we know. Besides... I am the Night. Others shall always doubt me. You may doubt me again. I ask only that you heed well your intuitions, from now on.",
	["0133?"] = "...I think I understand, now, Nyx. You've been here longer than the rest of us combined. You've seen this House go through a lot. Even before Lord Hades took his place. I never should have doubted you.",
	["0134"] = "You shall always be the best determiner of what is right about such matters, Megaera. Though, if you seek my blessings or encouragement in this particular pursuit, please rest assured... you have them both. You know the way, from here.",
	["0136"] = "You are already doing what you can to help, my son. Continue doing so. Matters are at stake here concerning you and all of us. Your support and choices in this shape the outcome that shall come to pass.",
	["0137?"] = "...We have another task for you.",
	["0142"] = "You have been served a Pact of Punishment, now, child. I thought to talk your father out of it, at first, but... it may serve to let you grow your power, even more.",
	["0143"] = "It is a point of fact. If you can overcome the conditions of the Pact, your influence throughout this realm shall surely grow. Though, do not overextend, of course.",
	["0144"] = "Hold, child. I have a message for you from my daughters, themselves. Concerning the Blade of the Underworld in your possession.",
	["0145"] = "They wish for me to impart to you these words, so that your blade, in turn, may hear them uttered from your lips: I see your kingly pardon from a prison of stone. Repeat them, and remember.",
	["0146"] = "I shall, child. Although, I'm certain they already know. Though, whether they are aiding you or this is simply what must come to pass, I cannot say.",
	["0147"] = "It means nothing to me at all, my child. Though, why do you invoke such names within this House? Who is this Skelly, and what do you presume is the connection that exists between us?",
	["0148"] = "Achilles moves throughout these chambers under my own shroud, if you must know. And thus you have in your possession the Infernal Arms. But, I have not exerted further influence than that. Is this skeleton to be trusted, then?",
	["0149"] = "Now that you have regained your access privileges to the administrative chamber, child, yes; that is a level of authority you hypothetically possess, again.",
	["0150"] = "That is a question only your father can answer, child. I cannot tell you more than you already know.",
	["0151"] = "You can be made aware. Though, use discretion, if and when you need to exercise this power. And make certain that the time is right. Now, are we understood?",
	["0152"] = "He has offered you aid, repeatedly. At first I saw it for a brazen act of bribery, but... try as I might, there was no deeper underpinning to his actions that I could detect. That is to say... the records you seek may be found in section sigma-phi-alpha, lower gamma folder.",
	["0153"] = "Your father found a certain peace from song, my child. Perhaps with this reprieve, our Orpheus shall reconsider and resume his craft.",
	["0154"] = "Your father's temperament is easier to navigate when he is in relatively better spirits. And my opinion is that punishing the court musician does not further your father's goal with him.",
	["0155"] = "That sounds to be an agreeable outcome for him. Though, his liberty is not the end of his rehabilitation. As his friend... please make certain he does not run afoul again of your father, child.",
	["0156"] = "Our court musician brings a certain peace to this abode, my child. But, you may discover, once you find his case files in section zeta-pi-omega, upper beta folder, that the consequences that he suffers may be quite in excess of his trespasses...",
	["0157"] = "You need not thank me, child. Your actions made this outcome possible. I merely did what anyone in my position would have done.",
	["0158"] = "Achilles... We would struggle to put someone comparable in his role. Though, be that as it may... epsilon-iota-theta. Rho folder, middle, I believe. You are certain about this, child?",
	["0159"] = "Oh, I can see them, my child, and I have. And it pleases me Achilles has earned some degree of respite from his servitude, for all his loyalty to our House. For what you have done for him, thank you.",
	["0160"] = "Your father is committed to his rules, and you released Achilles from his pact according to those rules. There is not much that even he can do about it save to have Achilles sign again.",
	["0161"] = "That I cannot say, child. It is peculiar having daughters who know every outcome that shall come to pass. It puts a strain on our relationship, and... I have learned never to ask they tell me more than they are willing to impart.",
	["0162"] = "It pleases me that you and Megaera have come to deeply understand each other, child. I must admit to you, it was my hope that you and she were capable of this result.",
	["0163"] = "I have no fear that Megaera shall be distracted, child. Besides; such matters are more likely to inspire, and to spur greater accomplishment. Although, the greater sense of contentment tends to be a sufficient end unto itself.",
	["0164"] = "I have no such fear for either one of you. You both are dedicated to your tasks. I trust your friendship can withstand your confrontations every now and then. For that is why the friendship blossomed, is it not?",
	["0166"] = "Then, in this you each achieved what you desired. I ask that you take care of my dear son. I often fear that he shall work himself too hard.",
	["0167"] = "Then, may the bonds of your friendship last for as long as this House shall reign beneath the earth, here in the dark. Take care of my dear son.",
	["0169"] = "...I do. Then, very well. But understand that your relationship with her does not preclude the need for her continual improvement with respect to her responsibilities.",
	["0171"] = "I was mistaken about both of you. That you would influence her in a harmful way, yet here, in point of fact, she has performed her duties with increasing skill. That she would fail to perform her role, or to learn well from her mistakes. Please do continue to look out for her.",
	["0172"] = "I sensed this outcome, and it pleases me. Though, you never would have simply discovered such a thing. They each are unique artifacts that must be given willingly if they are to retain their shape, and power.",
	["0174"] = "The severed gorgon head is not without redeeming attributes, my child. Though, I expected this companion would soon find its way to you, the way the two of you have grown attached. Thus, in one action, both of you have found encouragement.",
	["0175"] = "Among my many children, both those born to me and surrogate to me, you are one of the most thoughtful and most generous of all.",
	["0176"] = "Ah. A crystal bottle come all the way from the highest peaks of Mount Olympus to these depths within the earth. Your father always said he hated it.",
	["0177"] = "Ah, hahahaha. I accept this gift, with gratitude. This is a delicacy I have not experienced myself. Perhaps I may yet save it for appropriate occasions still to come. Thank you, my child.",
	["0178"] = "By the way, I meant to tell you, child. The Ambrosia that you gave me? Rather than hold onto it indefinitely, I decided recently to sample it. Your father's claims about its flavor are quite false. I have never tasted anything like it.",
	["0179"] = "You are persuasive like your mother, and determined like your father, child. But if you so insist, then I shall not deny myself the simple pleasures of this drink. Though rare is the occasion for it here.",
	["0180"] = "Oh. Then, the Three Fates are whimsical, indeed. When you were born, and I was filled with fear for what it meant for you to be alive, to be responsible for you... I must admit I did not guess that, one evening, you would provide for me both such a gift, and such a sentiment.",
	["0181?"] = "Nyx, along with giving you this bottle of Ambrosia here, there's something I have meant to say to you. The Three Fates have been very kind to me. Because, in denying me my birthmother... they gave me you. Without your steady presence here, I... can't imagine what it would be like.",
	["0182"] = "Child, I... know not exactly what you did, but... I detected faintly an attempt by Chaos to reach out to me. A message, merely at the edges of my consciousness, yet I felt certain it was there. But I could not discern it, otherwise. What does Chaos want from me?",
	["0183"] = "Now that the House is strong, and this realm orderly, I do not know. But I shall think upon it, child. Leave me, please.",
	["0185"] = "In the administrative chamber, you perhaps recall the Eldest Sigil there. Through it we have access directly to the darkest reaches of the realm. But not to Chaos, anymore. Not currently. Though, this is solvable, I think.",
	["0186"] = "That you were stripped of your authority is what makes this possible at all. It shall require a significant expenditure of Darkness. Then... the bridge to Chaos may be restored. So that I might travel again to visit them. Will you bring Darkness to the Sigil for me, please? When possible.",
	["0187"] = "At last. The bridge to Chaos is restored. Thank you so very much, my child. I shall be going, then. And I shall presently return. Please, have no fear. And now, farewell. I shall bring Chaos your kindest regards.",
	["0189"] = "It did. It did go well, my child, I... appreciated having had a chance to reconnect with my great ancestor. Thanks to your generosity, to both of us. We had to make up for a great deal of lost time.",
	["0190"] = "Chaos is comfortable in their realm. I may, however, visit every now and then. Keep them apprised of what unfolds up here. Beyond that... Chaos knows better than to exert too much influence upon this realm. Beyond having already formulated it, and everything.",
	["0192"] = "I asked she mind her own responsibilities. I fear she forgets herself, in this House. Though you have an informal air... you are the Prince! The only son of the Lord Hades, Fate-appointed master of this realm. You shall have the company of gods. Not severed gorgon heads.",
	["0193"] = "You do not fully know your place, my child. The gorgon-head most certainly does not know hers. Please focus on your task at hand, and leave her be.",
	["0194"] = "She was removed for insubordination, and repeated overextension and lack of proper judgment, child. Your affinity for her is the reason her removal was as amicable as it was.",
	["0195"] = "Her eagerness to please was to a fault. Perhaps your Olympian relatives require sacrifices, child, but this House requires efficiency, and nothing more.",
	["0196"] = "If you are bent on undermining my authority, go do so someplace else.",
	["0197"] = "I appreciate that you have calmed yourself, my child. As for the gorgon head, this House needs steady-tempered vigilance, not unthinking devotion. Despite repeated feedback, she refused to approach any aspect of her duties with restraint.",
	["0198"] = "She did not understand how to work properly. Despite all that she did, she ultimately was a burden to this House. There was no warning necessary on my part.",
	["0199"] = "...It seems you have more patience than I, child. And, I did not realize you cared. But do not ask again for me to rescind my decision. Are we understood?",
	["0200"] = "Your one more chance has certain stipulations, Dusa. If you think it is necessary to exceed the allotted time for your responsibilities, I expect you to ask. You are not the sole bearer of this House's fate. Your temperament toward your work is as important as the end result. Now then... I would ask that you return to your post.",
	["0201?"] = "Miss Nyx, you're...? Do I want my job again, I... wha, I, more than anything! This job, it, it means everything to me, I mean, working with you? You are the Night Itself! This place, and all of you, all of it, it's so amazing to me, and I just... I, just I want to help! Just, give me one more chance!",
	["0203"] = "You are most welcome. The orderliness of this House is a reflection of the realm as a whole. You have internalized this, and understood that a disciplined approach toward work is far more valuable than mere exertion of effort. Although, you understand the need for exertion, as well.",
	["0232?"] = "I know what must be done, regarding Chaos and myself, my child. It is not often that I ask for your assistance, but I need for you to do something for me, if you would hear me out.",
	["0234?"] = "...Understood, Mother. Commencing the assignment now.",
	["0235?"] = "You and my son... it pleases me to see the two of you have grown so close of late. Thanatos has always led a solitary life. He never would complain of it, and yet... I know he yearned for closeness, in his way.",
	["0238?"] = "No gift which you could bring me can exceed the value of our kinship, child. Though, it moves me to receive this offering.",
	["0239?"] = "...What I attempt to tell you, Nyx, is I am grateful. For our long-standing collaboration, here. My rule was thrust upon you and your kin. By all rights, you ought have undermined my every move. I often thought you would. Yet once Olympus and I severed ties... you stood by me still.",
	["0255?"] = "Nyx was just telling me some more about your early days, my son.",
	["0275?"] = "You are still in a difficult predicament, my child. And I, with you, in turn. Those on Olympus think you seek them, even now. That you are my own son by birth. Our deception, well intentioned as it was, has multiplied in size.",
	["0296"] = "You do not know. Ask her yourself, about her time with him. But... I have already said too much. And I cannot say more.",
	["0297"] = "It is through a concerted effort that the House thus thrives, for now. Though, it shall do so only through continued diligence on your behalf, and that of many others here. It is a good occasion to take brief reprieve. But we need you working to the best of your ability, here, Thanatos.",
	["0298?"] = "...The task is clear to me, Mother. I go. Your will be done.",
	["0299"] = "Pride has been the failing of so many mortals, child, and has brought low members of your family, as well. And yet... I am so very proud of you, for what you have achieved. I wanted you to be aware of that.",
	["0300"] = "I am eternally committed to this House. Long before your father came to rule, I was already here. When he arrived... I needed to do everything I could to keep order, and establish with Lord Hades an agreeable relationship. But, there is one more reason, besides that...",
	["0301"] = "A reasonable guess, and not without some truth to it, but no, my child. My reason for helping you is simpler than that. It is because I love you. You may not be born of me, but I raised you like one of my own. And I have cared for you as I am capable.",
	["0303?"] = "Persephone, the Queen... she has returned! I scarce believe it, child. You have brought her back, to all of us.",
	["0304"] = "Though reminiscent of an older time, it is now very different, child. For one thing... you are present, now. Unlike before.",
	["0305"] = "Everything is all right. Your birthmother... Persephone... her presence has been welcome here, I think.",
	["0307"] = "There can be no escape. Your father wishes that this reputation spread. So that the mortals and the shades never attempt what you were able to achieve.",
	["0308"] = "It is an honor to be working with you, child.",
	["0310"] = "Good times, I trust.",
	["0311"] = "We are pleased to have you back. Although, it shall be a difficult adjustment for you once again, I fear. For all of us.",
	["0312?"] = "...Persephone, my Queen... it has been far too long. Although, the passing of the time was very kind. It is an honor to see you again.",
	["0314"] = "But if you reveal to them the truth of everything... I fear the wrath they shall unleash. Perhaps not all of them, but some, at least, shall not take such deceptions well.",
	["0315"] = "Your birthmother is resourceful, certainly. Though can you say as yet, which sort of plan?",
	["0316?"] = "...I hear you, Mother, and obey. I will return when the task is complete.",
	["0318"] = "Persephone told them everything they needed to hear. Sometimes that is the only way, with family. Though, the Olympians... they are prone to their misunderstandings, are they not? This state of kinship may not last eternally.",
	["0319?"] = "It was a privilege to meet your relatives at last, child. Athena, Ares, and the rest. Confronted face-to-face, they were much more agreeable than I expected. A night we shall remember, was it not?",
	["0321"] = "That sounds quite pleasant for someone who values brightness, I suppose. Well, then... I trust your visits are worthwhile for the both of you.",
	["0322"] = "Hypnos still is learning independence, child. Thus, I have decided it is best to keep my distance from him temporarily, else he shall continue to rely upon me, even for completing the most rudimentary requests. We have agreed he shall not call upon me for the time being.",
	["0323"] = "Based on his rate of progress, I suspect his education shall have been complete well before the dawning of the next age.",
	["0324"] = "We have, thank you, my child. Goddess Athena is reputed to be wise, and so she was the one I felt was the most likely to listen to reason, understand my view, and ultimately have a willingness to help. It is most fortunate that I was not mistaken about her.",
	["0325"] = "She is wise, child. It is precisely for that reason I expected she would understand.",
	["0326"] = "Charon and I have not lately taken opportunities to correspond. But he has always been among the least dependent of my children, other than perhaps only the Fates. This much I know and can assure to you: He always is content to steer his boat.",
	["0327"] = "No. He is the one to thank. Do not mistake his lack of speech for lack of cleverness. He serves this House as I do. But he does not answer to me.",
	["0328"] = "Ah, yes, the god of war. Among all the Olympians, he often struck me as much more accepting of our kind, born of the Underworld.",
	["0329"] = "I take an interest in whomever I take interest in, my child. I thank you for the message.",
	["0330"] = "I shall, thank you, my child. If the god of war is thus preoccupied with me, well then, perhaps he shall be slower to send droves of mortals to our doorstep here.",
	["0331"] = "Do not concern yourself with my ability to navigate my interpersonal relationships, my child. It pleases me Lord Ares told you this. Those of Olympus rarely say such things, to any of us here.",
	["0332"] = "His interest in the Underworld is genuine, and he does not regard me as beneath him, even if the technicality exists. The Olympians and the chthonic gods... we have much left to learn of one another's kind.",
	["0333"] = "You have repeatedly received such contact, all despite your father's wishes, child.",
	["0334"] = "What is your concern, exactly, child? Speak plain with me, or else take not my time.",
	["0335"] = "You do not understand the basis of our friendship, child. Lord Ares may not meet the moral standard of the mortals who hate him, or Olympians who shun him, but to me? He is cordial and eager to learn. I am quite capable of forming my own views on him.",
	["0336"] = "Thank you, my child. We may seldom have occasion to encounter one another, he and I, but it is good to have another friend upon Olympus. Even if goddess Athena and he are not on the best of terms.",
	["0337"] = "Hades. When have I even once been unaware of precisely what I mean to do? I shall bring no harm to the Queen, and neither shall your son.",
	["0338"] = "Child! Zagreus. Do you intend to betray the presence of your birthmother to the Olympians?",
	["0339"] = "Precisely how I trusted him to get us to this point.",
	["0340"] = "I am the Night Itself, as you well know, Hades. As I declared to you when first we met: I shall stand by your side, so long as you remain the fate-appointed ruler of this realm.",
	["0341"] = "Your services were always welcome, here. Please acclimate yourself at your own rate. I am available to answer any questions you may have at any time.",
	["0342"] = "I can remember feeling similar emotions at the time. However, it is quite unnecessary to give thanks to me this way. You are the Queen, safely returned where you belong. I did what anybody would have in my place.",
	["0343?"] = "...I just don't know how I can ever repay you. For raising him. For everything. After I left... besides old Cerberus, I think maybe I missed you most of all.",
	["0344"] = "You are to thank for this outcome as much as I. Perhaps more so. For I have little choice but to serve this House. I was created in this realm, and it is everything to me. But you? Your loyalty could not have been assumed.",
	["0345"] = "Nevertheless, given the circumstances of your life and servitude, you need not have given so much of yourself. The greatness of your mortal days followed you into death.",
	["0346"] = "This realm remains enshrouded and obscure by my design and by your father's will, my child. Tell me, what would be the benefit of the attention you would seek?",
	["0347"] = "Obscurity is not a weakness, child. Are we understood? Seek to be valuable, not to be known. If you are valuable, then fame or notoriety can be a consequence. Should they become a burden... I can help.",
	["0348"] = "Through any setback, you are always welcome here with me, dear child.",
	["0349"] = "The nature of this realm, my child, is not fully known or understood, not by anyone within it or above.",
	["0350"] = "There is no setback which you cannot overcome.",
	["0351"] = "All here is well at present, child.",
	["0352"] = "The House stands strong from all your labors, child.",
	["0353"] = "You bring me pride through your accomplishments.",
	["0354"] = "Go, and serve this House.",
	["0355"] = "May Thanatos assist you should you cross his path.",
	["0356"] = "Remain unseen, my child.",
	["0357"] = "The Queen Persephone must be so proud of you.",
	["0358"] = "Go, in honor of your birthmother, the Queen.",
	["0359"] = "This House is stronger with the Queen returned.",
	["0360"] = "Honor the Queen, my child.",
	["0361"] = "Your father's spirits have been better as of late.",
	["0362"] = "Your birthmother awaits. Go find her, child.",
	["0363"] = "Seek out your birthmother again, my child.",
	["0364"] = "Persephone awaits above.",
	["0365"] = "I know for certain your birthmother waits for you.",
	["0366"] = "Go. You know precisely where to find her now.",
	["0367"] = "Chaos and I have much catching up to do.",
	["0368"] = "How interesting to see you here, my child.",
	["0369"] = "Please go ahead and do not mind me, child.",
	["0370"] = "Thank you for keeping Chaos company.",
	["0371"] = "Go forth, bearing the mark of Chaos.",
	["0372"] = "I am afraid I cannot help you now.",
	["0373"] = "You shall discover what you seek when it is time.",
	["0376"] = "I am preoccupied, so please excuse me, child.",
	["0377"] = "My focus is on other matters at this time.",
	["0379"] = "Please leave me to my current task at hand.",
	["0380"] = "Let us communicate again some other time.",
	["0383"] = "The risk is not to me. I expected the Olympians would involve themselves in this, eventually. Reveal to them no more than they already know. Are we understood?",
	["0384?"] = "Thank you for thinking of me for this task. I'll make it happen shortly.",
	["0386"] = "The risk was not to me. It was inevitable that the Olympians would involve themselves in this. The only question was how.",
	["0388"] = "They are helping you because you are family. Family with whom they do not yet have a complicated past.",
	["0389"] = "When your birthmother departed, I bent the light for her, shrouding her path, though I myself could see it. I trust she remains there, and that I am not betraying her confidence by telling you.",
	["0390"] = "And you would not have gone far, child. Your father is too proud to accept assistance in personal matters. Do not cede the advantage that you have.",
	["0391"] = "I shall do everything within my power to prevent this, as shall you.",
	["0393"] = "Oh, my child... I say this seldomly, but... I did not know. Or... I did not wish to believe... that the surface would have such an effect on you. But it seems you share your father's fate, after all.",
	["0394"] = "So I now presume. You are bound to this realm by powers greater even than mine. Tell me something... if you knew that you could only see Persephone for but a moment's time... would you still make the journey to her, there?",
	["0395"] = "Then, go and ask them, child. Steady your resolve, and find her there, again. And use well what brief time you have with one another, whilst you can. As mortals do.",
	["0396"] = "I swore a binding oath never to say, child. I have already circumvented it as much as can be done. Know that we... that I acted with only her wellbeing in mind. As well as yours.",
	["0398"] = "There are many things that I am not at liberty to speak of, child. Through my own binding choice. These circumstances are among them. Suffice it to say that your revival... required the extent of my ability. And considerable time.",
	["0399"] = "Silence. Tempt not my daughters thus.",
	["0400"] = "No. There was not. She has been in danger, all along. I concealed her, yes. Even from me. But, it is not enough. I do not think that you could have found her without the Olympians. And, if I did not reveal your existence to them... if they discovered who you are... it would be worse.",
	["0401"] = "The Olympians maintain belief that you are trying to reach them. I trust we can sustain this understanding for a long, long time. Perhaps not forever, but... long enough to discover a solution. Perhaps with your birthmother's help.",
	["0402"] = "Do not question my power, Hades. Your son was bound to be discovered the closer he came to the surface. The Olympians are pleased to know they have a distant relative, and bid him welcome to their mountain. That is all. Their influence is very limited.",
	["0403"] = "You would speak to me of foolish mistakes? You cannot change the course that has been set. Try all you like.",
	["0405"] = "She did not feel that she belonged. It was a very difficult adjustment she was forced to make. And... she feared that she would inevitably end up caught between Olympus and this realm. That she might start a war.",
	["0407"] = "Oh. That is a fair-enough assessment. What shall you do?",
	["0408?"] = "What is the matter, child? I sense your distress, not the specific cause.",
	["0409"] = "Your father was different with Persephone, to some extent. He has always been as you know him, yet... her lightness... it affected even him, I think. And he knows... that he was better with her, than without.",
	["0410?"] = "Father loved her, didn't he? Mother, I mean. Faith like that... he's just stubborn enough to hold onto the idea of her, isn't he? Though, what she saw in him, I'm not sure.",
	["0419"] = "None of Charon's brothers ever dared fight with him whilst growing up. Why would you fathom such a ruinous idea, child?",
	["0420"] = "Probably not. For it is unnecessary. Likely he appreciates having an adversary, in his own way. Few would so much as dare.",
	["0421"] = "Charon serves only this realm, child. And, he is very trustworthy. I suppose that it is also possible he has some affection for the Queen, if not for you.",
	["0422"] = "I am certain I know nothing of what you mean, Achilles. Though, your continued service here is more than welcome. The honor is mine.",
	["0423"] = "They are your sisters. They are part of your life, whether you like it or not. Your relationship with them is yours to mold.",
	["0424"] = "I have a lot more faith in you, Megaera. There are many obstinate personalities with whom we regularly interact. Thus, we do what is possible.",
	["0425"] = "Do not mistake them for their unassuming look. Within them is the strength of an unbreaking bond between two souls conjoined.",
	["0426"] = "I am amenable to the consonance of his harmonies, child.",
	["0427"] = "Remember what we previously spoke of, Hypnos. Do not address me thus whilst we are here. Conduct yourself as befitting a servant of the House of Hades... and, continue practicing your independence, please.",
	["0429"] = "Commended by me. I cannot always look after all of my children, as you know. It falls upon them to take care of themselves, as well as their obligations to our domain. As your mother... it is reassuring to see that you are capable.",
	["0430"] = "You are my son. It is to be expected. However... I know it is not effortless, to be of use. Continue to do well. I shall be watching.",
	["0431"] = "I sense all of the minor prophecies described within the Fated List have been fulfilled...? I do not understand how that is possible.",
	["0432"] = "The Fates are always at their weaving. To have caught up with their designs... well, I should think that they shall have to learn to weave a little faster, perhaps.",
	["0433"] = "I think you are, as well. Then, it shall be as you wish.",
	["0434"] = "To shine was never quite my strongest suit. During the dawn of creation, there was much to do. This place... all that you see around you... it was more my leaning. Chaos understands that better, now. As for me, the work helped me to know which limits I have.",
	["0435"] = "Come, child. We each have our limits.",
	["0436"] = "I know you care for her, child. And I admit I retain several concerns. Not only about the appropriateness of her conduct, but of her reckless inexperience. I do, however, see the possibility that she can work through these issues. Perhaps with your support.",
	["0439"] = "No. They are required elsewhere. It is for the best. Some of my children are not on speaking terms with one another, or with me. As a mother... one has her victories, and her defeats.",
	["0441"] = "You misunderstand. I am grateful. These changes... I would not have commissioned them, myself. But, seeing them now... I appreciate their presence. You have a discerning eye.",
	["0442"] = "I... hardly think that Chaos would attend any festivity of ours. I am uncertain that they even could. Even more doubtful that they would want this. However... if you truly wish to ask, proceed.",
	["0443"] = "Only a little bit. The first communication we have had in quite some time. It went better than expected. Perhaps they and I can continue the conversation at some point. Thank you for your initiative, child.",
	["0444"] = "Nonsense, child. Our records must be kept up-to-date. You merely observed that several were long past due. Not even your father can argue with that.",
	["0445"] = "You know your father does not like it when Nectar is doled out on the premises, dear child. However, I am not he... and I wished, regardless, to provide to you a token of my affection.",
	["0446"] = "Chaos and I have so much left to discuss.",
	["0447"] = "It is comforting to be here again, in such darkness.",
	["0448"] = "I shall see you back at the House soon, child.",
	["0449"] = "It is odd to have returned to where I was born.",
	["0450"] = "We are pleased to see you here, however briefly.",
	["0451"] = "As Chaos cannot visit us as easily, now I can visit them.",
	["0455"] = "...Your expertise is needed once again.",
	["0466"] = "She has departed once again. Your birthmother the Queen. Although, it was not as difficult to see her off, this time. Knowing she shall return.",
	["0467"] = "Do not despair. We have ways of watching over her. Not that I expect anything untoward to happen, but... well, with your family, one learns to take precautions, as you know.",
	["0468"] = "So shall I. But it shall not be long, I think.",
	["0470"] = "The Mirror has little to do with your power, let alone your capability. You may deactivate its effects and see for yourself. It merely gave you greater opportunity to learn. And you shall continue to do so.",
	["0473"] = "Surely that is not so. Think back on when you started all of this. You now know so much more. Are capable of so much more.",
	["0462?"] = "Oh we're busy just formulating more of our dark schemes together, Zagreus.",
	["0052?"] = "It seems I failed once again to persuade Nyx to take some personal time!",
	["0028"] = "How may I help you, child?",
	["0029"] = "May I assist you somehow, child?",
	["0030"] = "Is there something I can do for you, my child?",
	["0031"] = "Is anything the matter, child?",
	["0033"] = "Might I be of assistance, my child?",
	["0034"] = "What might I do to ease your burden, child?",
	["0035"] = "It shall be done, child.",
	["0036"] = "It shall be so.",
	["0037"] = "As you wish, my child.",
	["0038"] = "I am pleased to oblige.",
	["0040"] = "Your will be done, my child.",
	["0041"] = "Your wish is granted, child.",
	["0042"] = "Very well, my child.",
	["0043"] = "I hear you, child.",
	["0044"] = "Certainly, my child.",
	["0049"] = "A gift as beautiful as this requires reciprocity, dear child. I wished, regardless, to provide to you a token of my love.",
	["0050"] = "An offering, to me, dear child? Then, it is only reasonable that I make to you an offering, in kind. I thank you, and I wish for you to have this.",
	["0051"] = "I am unable to accept such a kind offering, dear child, unless you likewise take this trifle of a gift?",
	["0052"] = "Hmm.",
	["0053"] = "Haaaaah.",
	["0054"] = "You have come home.",
	["0055"] = "You are home.",
	["0056"] = "A welcome sight.",
	["0057"] = "Hmm, hmmm, hmm-hmmmm.... hmm, hmm, hmmm-mmm-mmm-mmm-mmm, mmmm....",
	["0067"] = "Tell me something, child. Has the goddess Athena thus been true to her word, in her willingness to lend you her support?",
	["0067ALT"] = "Do not despair and hold to your resolve, child. Tell me something; has the goddess Athena thus been true to her word, in her willingness to lend you her support?",
	["0068"] = "It gladdens me to hear it. Seldom do Olympians consort with those born of the Underworld, yet your circumstances seemed due cause for an exception. She shall make a powerful ally.",
	["0074"] = "We each have our commitments to this House, daughter. There is no shame in yours. And whilst your sisters are away, you bear their burden of responsibility, as well.",
	["0076"] = "...and so, who else is there to be depended on...? Although, I urge you also to look inwardly, daughter. How you approach your work is vital to the end result.",
	["0079"] = "Hah, haha. She is a daughter to me, as you are my child, child. I am the night itself. Past that, I am unable to explain. Though I am pleased to see the two of you on better terms of late.",
	["0081"] = "We have an understanding, Lord. I am committed to this realm, and to this House. And I remain, as ever, in your debt.",
	["0082"] = "My relationship with him remains unchanged, my lord. He has my full support, and always shall. You must know this. He wishes now to leave. I shall make no attempt to stop him.",
	["0090"] = "Do not despair and hold to your resolve, child. Tell me something; has the goddess Athena thus been true to her word, in her willingness to lend you her support?",
	["0091"] = "Do not despair, child. Such setbacks are inevitable, and may be overcome with effort and with time. Though, tell me, has the goddess Athena thus been true to her word?",
	["0092"] = "It was the least that I could do. The Olympians typically do not involve themselves in Underworld affairs, yet your circumstances seemed due cause for an exception. They shall make powerful allies. But, reveal to them no more than they already know. For all our sakes.",
	["0096"] = "It is more than all right, my child.",
	["0099"] = "Your mother was a spirited woman. What can I tell you, child? I cared for her and her predicament. When she departed, I bent the light for her, shrouding her path, though I myself could see it. I trust I now do not betray her confidence by telling this to you.",
	["0107"] = "We all do that which is within our power.",
	["0115"] = "Do as you must. Your victory is within reach.",
	["0133"] = "I do know where to find you, Megaera.",
	["0135"] = "It is yours for the taking.",
	["0137"] = "Farewell.",
	["0138"] = "I trust you are not wrong, my son. I trust you are not wrong. And, as for what I think... it pleases me to see your disposition has been better, as of late. You work so very hard.",
	["0139"] = "To be distracted from one's work from time to time has its uses, Thanatos. You may find your work shall benefit over the longer term. Though, if that were your only focus, we would not be having this discussion, now.",
	["0140"] = "Your father fell to you, as once his father fell to him. Although, you were substantially more merciful, it seems, since he is here. I know it is a bitter victory, at best.",
	["0141"] = "If you can surpass him once, then you have the capacity to achieve your true goal. Not that I ever doubted you, except... I know the effort that it must have taken, to have come this far.",
	["0173"] = "Do not mistake them for their unassuming look. For they are catalysts of extraordinary power. The unbreaking bond between two souls conjoined.",
	["0181"] = "I love you, too, my child.",
	["0201"] = "Do your best work.",
	["0204"] = "Child.",
	["0205"] = "My child.",
	["0206"] = "You have returned.",
	["0207"] = "You are returned.",
	["0208"] = "It is you.",
	["0209"] = "You are back.",
	["0210"] = "You are here.",
	["0211"] = "A setback, then.",
	["0212"] = "Ah.",
	["0213"] = "Be unseen.",
	["0214"] = "There you are.",
	["0215"] = "You have done well.",
	["0216"] = "You broke free.",
	["0217"] = "You reached the surface...",
	["0218"] = "Did you find her?",
	["0219"] = "Well done.",
	["0220"] = "At last.",
	["0221"] = "A word.",
	["0222"] = "A word, child?",
	["0223"] = "A word, please.",
	["0224"] = "Hold a moment.",
	["0225"] = "A moment.",
	["0226"] = "Here.",
	["0227"] = "Child?",
	["0228"] = "Night and Darkness, guide you.",
	["0229"] = "It shall be done.",
	["0230"] = "As you say.",
	["0231"] = "As you will.",
	["0232"] = "So shall it be.",
	["0233"] = "It shall be so.",
	["0234"] = "Very well.",
	["0235"] = "Then very well.",
	["0236"] = "As you wish.",
	["0237"] = "As you will.",
	["0238"] = "I am grateful.",
	["0239"] = "You have my gratitude.",
	["0240"] = "Thank you, my child.",
	["0241"] = "It is appreciated, child.",
	["0242"] = "I thank you for this, child.",
	["0243"] = "You are too kind.",
	["0244"] = "How very kind of you.",
	["0245"] = "How very thoughtful, child.",
	["0246"] = "I have something for you.",
	["0247"] = "This is for you.",
	["0248"] = "This belongs to you.",
	["0249"] = "For you, my child.",
	["0250"] = "Please take this, child.",
	["0251"] = "Please, this is yours.",
	["0252"] = "For you.",
	["0253"] = "Here.",
	["0254"] = "There.",
	["0255"] = "Mmm.",
	["0256"] = "Yours.",
	["0257"] = "Grow.",
	["0258"] = "Darkness.",
	["0259"] = "That is unfortunate.",
	["0260"] = "An undesired outcome.",
	["0261"] = "The Fates have been unkind.",
	["0262"] = "Another setback to be overcome.",
	["0263"] = "How disappointing.",
	["0264"] = "I feared this would occur.",
	["0265"] = "I am displeased.",
	["0266"] = "I certainly do not approve of this.",
	["0267"] = "You would be wiser not to test my patience thus.",
	["0268"] = "It is unwise to thusly anger me.",
	["0269"] = "Such utter carelessness.",
	["0270"] = "Such actions I cannot abide.",
	["0271"] = "A truly senseless act.",
	["0272"] = "Please leave me for now, child.",
	["0273"] = "Please leave me be.",
	["0274"] = "I wish to be left alone.",
	["0275"] = "Truly...?",
	["0276"] = "By the Darkness...",
	["0277"] = "Can it be...?",
	["0278"] = "But this cannot be.",
	["0279"] = "Are you most certain...?",
	["0280"] = "I scarce believe it...",
	["0281"] = "Can it be true...?",
	["0282"] = "I knew that you were more than capable.",
	["0283"] = "I never doubted you.",
	["0284"] = "I had envisioned that you would succeed.",
	["0285"] = "Excellently done.",
	["0286"] = "Skillfully executed work.",
	["0287"] = "Your father fell to you, as once his father fell to him. Although, you were substantially more merciful. I know it is a bitter victory, at best. Though, tell me, more importantly, then... did you find her? Beyond a path well hidden even from me?",
	["0288"] = "You may yet ask them, child. If you were able to locate her once... is it not true that you could do so once again? Go, ask your questions of her, all of them. As many chances as it takes.",
	["0289"] = "You can. You already have. Go find her, child. She cannot risk returning here. But she awaits you, now.",
	["0290"] = "My child... it is difficult for me to say this, but... I simply did not know. My influence extends up to the surface, yes. But I have never been there for myself. So I did not anticipate that it would have such an effect on you. It seems to me you share your father's fate.",
	["0291"] = "So I now presume. You are bound to this realm by powers even greater than my own. Tell me something... if you knew you that could only see Persephone for but a moment's time... would you still make the journey to her, there?",
	["0292"] = "Then, steady your resolve, and find her there, again. And use well what brief time you have with one another, whilst you can. As mortals do.",
	["0293"] = "Wait...",
	["0294"] = "Child, quickly now, before you go. Although I know your time upon the surface is too brief, should you even achieve your goal, at all... would you please tell Persephone that I was true to her? And, that I think fondly on the time she spent with us? Please tell her that, for me.",
	["0295"] = "She did not feel that she belonged, I think. It was a very difficult adjustment she was forced to make. And... she feared that she would inevitably end up caught between Olympus and this realm. That she might start a war.",
	["0298"] = "Thank you, my son.",
	["0303"] = "Together, let us find out.",
	["0312"] = "I do.",
	["0316"] = "Indeed.",
	["0319"] = "A sound idea.",
	["0343"] = "Precisely, yes.",
	["0375"] = "In this I am unable to assist you, child.",
	["0378"] = "I cannot simultaneously speak and channel darkness, child.",
	["0381"] = "It was the least that I could do. The Olympians shall make powerful allies. But, reveal to them no more than they already know. For all our sakes.",
	["0384"] = "Then, go.",
	["0408"] = "Good.",
	["0410"] = "She did, did she...?",
	["0411"] = "Zagreus.",
	["0412"] = "Zagreus?",
	["0413"] = "Wait, child.",
	["0414"] = "Welcome to Chaos.",
	["0415"] = "You found us.",
	["0416"] = "All of us, here.",
	["0417"] = "You are here.",
	["0418"] = "What a surprise.",
	["0452"] = "I have a new assignment for you, child.",
	["0453"] = "There is a matter that requires your attention.",
	["0456"] = "Another situation has arisen, child.",
	["0457"] = "I require your assistance with something, child.",
	["0458"] = "<Chuckle>",
	["0459"] = "<Chuckle>",
	["0460"] = "<Laugh>",
	["0461"] = "<Laugh>",
	["0462"] = "<Smirk>",
	["0463"] = "<Sigh>",
	["0464"] = "<Sigh>",
	["0465"] = "Hrmm.",
	["0471"] = "Yes.",
	["0474"] = "Well done, child.",
	["0475"] = "A commendable result.",
	["0476"] = "You have done well.",
	["0477"] = "Excellent work.",
	["0478"] = "To your continued success.",
	["0479"] = "The realm is strong.",
	["0480"] = "The House is in order.",
}
